import React from 'react';
import {reduxForm} from 'redux-form'
import {maxLengthCreator, required} from "../../utils/validators/validators";
import {Area, createField} from "../Common/FormsControls/FormsControls";
import {connect} from "react-redux";
import {login} from "../../redux/auth-reducer";
import Redirect from "react-router-dom/es/Redirect";
import styles from '../Common/FormsControls/FormsControls.module.css'
import Typography from "@material-ui/core/Typography";
import Link from "@material-ui/core/Link";
import {makeStyles} from "@material-ui/styles";
import Container from "@material-ui/core/Container";
import CssBaseline from "@material-ui/core/CssBaseline";
import Avatar from "@material-ui/core/Avatar";
import Grid from "@material-ui/core/Grid";
import Box from "@material-ui/core/Box";




const maxLength30 = maxLengthCreator(30);
const Input = Area('input')

const Copyright = () => {
    return (
        <Typography variant="body2" color="textSecondary" align="center">
            {'Vitaliy Shiryaev 2020 © '}
            <Link color="inherit" href="https://www.youtube.com/playlist?list=PLcvhF2Wqh7DNVy1OCUpG3i5lyxyBWhGZ8">
                IT-KAMASUTRA
            </Link>
        </Typography>
    );
}

const useStyles = makeStyles((theme) => ({
    paper: {
        backgroundImage: "url(Components/img/07.jpg)",
        backgroundRepeat: "no-repeat",
        // marginTop: theme.spacing(8),
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
    },
    avatar: {
        // margin: theme.spacing(1),
        // backgroundColor: theme.palette.secondary.main,
    }
}));




const LoginForm = ({handleSubmit, error, captchaUrl}) => {
    return <form onSubmit={handleSubmit}>
        {createField('Input', 'Email', "email", "text", [required, maxLength30])}
        {createField('Input', 'Password', "password", "password", [required, maxLength30])}
        {createField('Input', null, "rememberMe", "checkbox", null, 'remember me')}
        {captchaUrl && <img src={captchaUrl}/>}
        {captchaUrl && createField('Input', 'Enter symbols from image', 'captcha', "text", [required])}

        {error && <div className={styles.formSummeryError}>
            {error}
        </div>}
        <button>
            Login
        </button>

    </form>
};

const LoginReduxForm = reduxForm({
    form: 'login'
})(LoginForm);

const Login = (props) => {
    const classes = useStyles();
    const onSubmit = (formData) => {
        props.login(formData.email, formData.password, formData.rememberMe, formData.captcha)
    }
    if (props.isAuth) {
        return <Redirect to={'/profile'}/>
    }
    // return <div>
    //     <h1>LOGIN</h1>
    //     <LoginReduxForm onSubmit={onSubmit} captchaUrl={props.captchaUrl}/>
    // </div>

    return (
    <Container component="main" maxWidth="xs">
        <CssBaseline/>
        <div className={classes.paper}>
            <Avatar className={classes.avatar}>
                5
            </Avatar>
            <Typography component="h1" variant="h5">
                Sign in
            </Typography>
            <Grid container>
                <Link href="https://social-network.samuraijs.com/signUp" target={"#"} variant="body2">
                    {"Don't have an account? Sign Up"}
                </Link>
            </Grid>

        </div>
        <Box mt={8}>
            <Copyright/>
        </Box>
    </Container>
    );

}

const mapStateToProps = (state) => ({
    isAuth: state.auth.isAuth,
    captchaUrl: state.auth.captchaUrl
})

export default connect(mapStateToProps, {login})(Login);

